 import type { UseQueryOptions } from "@tanstack/react-query";
 import { useQuery } from "@tanstack/react-query";
 import type { ColumnDef } from "@tanstack/react-table";
 import {
   flexRender,
   getCoreRowModel,
   useReactTable,
 } from "@tanstack/react-table";
 import { Archive, Search } from "lucide-react";
 import { parseAsJson, useQueryState } from "nuqs";
 import { useMemo, useRef, useState } from "react";
 import { z } from "zod";

 import { DataTableFilter } from "@/components/data-table-filter";
 import type {
   ColumnConfig,
   FiltersState,
 } from "@/components/data-table-filter/core/types";
 import { useDataTableFilters } from "@/components/data-table-filter/hooks/use-data-table-filters";
 import { FilterViewTabs } from "@/components/filter-view-tabs";
 import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
 import type { FilterViewDisplay } from "@/db-schemas";
 import { rpc } from "@/rpc/client";

 import { Button } from "../ui/button";
 import { Input } from "../ui/input";
 import {
   Table,
   TableBody,
   TableCell,
   TableHead,
   TableHeader,
   TableRow,
 } from "../ui/table";
 import NavLayout from "./nav-layout";

 type FilterViewRow = {
   createdAt: Date | null;
   display: FilterViewDisplay;
   domain: string;
   id: string;
   isSystemCreated: boolean;
   label: string;
   refine: FiltersState;
   updatedAt: Date | null;
 };

 const filtersSchema = z.custom<FiltersState>((val): val is FiltersState =>
   Array.isArray(val),
 );

 function filterKey(f: FiltersState[number]) {
   return `${f.columnId}::${f.operator}`;
 }

 function filtersEqual(a: FiltersState[number], b: FiltersState[number]) {
   return (
     a.columnId === b.columnId &&
     a.operator === b.operator &&
     a.type === b.type &&
     a.values.length === b.values.length &&
     a.values.every((v, i) => v === b.values[i])
   );
 }

 function mergeFilters(base: FiltersState, overrides: FiltersState) {
   const overrideMap = new Map(overrides.map((o) => [filterKey(o), o]));
   const result: FiltersState = [];

   for (const b of base) {
     const key = filterKey(b);
     if (overrideMap.has(key)) {
       const override = overrideMap.get(key);
       if (override && !filtersEqual(b, override)) {
         result.push(override);
       }
       overrideMap.delete(key);
     } else {
       result.push(b);
     }
   }

   for (const o of overrideMap.values()) {
     result.push(o);
   }

   return result;
 }

 function computeOverrides(base: FiltersState, effective: FiltersState) {
   const overrides: FiltersState = [];
   const baseMap = new Map(base.map((b) => [filterKey(b), b]));

   for (const f of effective) {
     const key = filterKey(f);
     const baseFilter = baseMap.get(key);
     if (!baseFilter || !filtersEqual(baseFilter, f)) {
       overrides.push(f);
     }
   }

   return overrides;
 }

 export function DataViewLayout<
   TItem,
   TInput extends Record<string, unknown>,
   TColumns extends ReadonlyArray<ColumnConfig<TItem, any, any, any>>,
 >({
   baseUrl,
   columnsConfig,
   domain,
   emptyMessage = "No items found",
   filtersToInput,
   getRowId,
   label,
   listProcedure,
   onRowClick,
   rightItems,
   searchPlaceholder = "Search...",
   columnDefs,
-  data: usersData,
+  usersData,
 }: {
   baseUrl: string;
-  data: TItem[];
+  usersData?: { items: Array<{ id: string; image: string | null; name: string | null }> };
   columnDefs: ColumnDef<TItem>[];
   columnsConfig: TColumns;
   domain: string;
   emptyMessage?: string;
   filtersToInput: (
     filters: FiltersState,
   ) => Omit<TInput, "cursor" | "limit" | "search">;
   getRowId: (row: TItem) => string;
   label: string;
   listProcedure: {
     queryOptions: (opts: { input: TInput }) => UseQueryOptions;
   };
   onRowClick?: (row: TItem) => void;
   rightItems?: React.ReactNode;
   searchPlaceholder?: string;
 }) {
   const [search, setSearch] = useState("");
   const [cursor, setCursor] = useState<string | undefined>();

   const [view] = useQueryState("view");
   const [urlFilters, setUrlFilters] = useQueryState<FiltersState>(
     "filters",
     parseAsJson(filtersSchema.parse).withDefault([]),
   );

   const { data: filterViewsData } = useQuery({
     ...rpc.filterView.list.queryOptions({ input: { domain } }),
     enabled: !!view,
   });

   const filterOptions = useMemo(() => {
     const assigneeOptions = (usersData?.items ?? []).map((u) => ({
       icon: (
         <Avatar className="size-4">
           <AvatarImage src={u.image ?? undefined} />
           <AvatarFallback>{u.name?.[0] ?? "?"}</AvatarFallback>
         </Avatar>
       ),
       label: u.name ?? "Unknown",
       value: u.id,
     }));

     const archivedOptions = [
       {
         icon: <Archive className="size-4" />,
         label: "Archived",
         value: "true",
       },
       { label: "Active", value: "false" },
     ];

     return { archived: archivedOptions, assigneeId: assigneeOptions };
   }, [usersData]);

   const filterViews = (filterViewsData ?? []) as FilterViewRow[];
   const activeView = view ? filterViews.find((v) => v.id === view) : null;
   const baseFilters = activeView?.refine ?? [];

   const effectiveFilters = view
     ? mergeFilters(baseFilters, urlFilters)
     : urlFilters;

   const updateFilters: React.Dispatch<React.SetStateAction<FiltersState>> = (
     next,
   ) => {
     const resolved = typeof next === "function" ? next(effectiveFilters) : next;

     if (view) {
       const overrides = computeOverrides(baseFilters, resolved);
       setUrlFilters(overrides.length > 0 ? overrides : null);
     } else {
       setUrlFilters(resolved);
     }
   };

   const baseInput = useMemo(
     () => filtersToInput(effectiveFilters),
     [effectiveFilters, filtersToInput],
   );

   const prevBaseInput = useRef(baseInput);
   if (prevBaseInput.current !== baseInput) {
     setCursor(undefined);
     prevBaseInput.current = baseInput;
   }

   const {
     columns,
     filters: filterState,
     actions,
     strategy,
   } = useDataTableFilters({
     columnsConfig,
     data: [] as TItem[],
     filters: effectiveFilters,
     onFiltersChange: updateFilters,
     options: filterOptions as any,
     strategy: "server",
   });

   const queryResult = useQuery(
     listProcedure.queryOptions({
       input: {
         ...baseInput,
         cursor,
         limit: 20,
         search: search || undefined,
       } as unknown as TInput,
     }) as UseQueryOptions<{
       items: TItem[];
       nextCursor?: string;
     }>,
   );

   const data = queryResult.data;
   const isLoading = queryResult.isLoading;

   const items = data?.items ?? [];
   const nextCursor = data?.nextCursor;

   const table = useReactTable({
     columns: columnDefs,
     data: items,
     getCoreRowModel: getCoreRowModel(),
     getRowId: (row) => getRowId(row as TItem),
   });

   return (
     <NavLayout
       baseUrl={baseUrl}
       label={label}
       leftItems={<FilterViewTabs domain={domain} />}
       rightItems={rightItems}
     >
       <div className="space-y-4">
         <div className="flex items-start gap-2">
           <div className="relative flex-1">
             <Search className="absolute top-2.5 left-2.5 size-4 text-muted-foreground" />
             <Input
               className="pl-8"
               onChange={(e) => {
                 setSearch(e.target.value);
                 setCursor(undefined);
               }}
               placeholder={searchPlaceholder}
               value={search}
             />
           </div>
           <DataTableFilter
             actions={actions}
             columns={columns}
             filters={filterState}
             locale="en"
             strategy={strategy}
           />
         </div>

         <div className="rounded-lg border bg-card">
           <Table>
             <TableHeader>
               {table.getHeaderGroups().map((headerGroup) => (
                 <TableRow key={headerGroup.id}>
                   {headerGroup.headers.map((header) => (
                     <TableHead key={header.id}>
                       {header.isPlaceholder
                         ? null
                         : flexRender(
                             header.column.columnDef.header,
                             header.getContext(),
                           )}
                     </TableHead>
                   ))}
                 </TableRow>
               ))}
             </TableHeader>
             <TableBody>
               {isLoading ? (
                 <TableRow>
                   <TableCell
                     className="text-center text-muted-foreground"
                     colSpan={columnDefs.length}
                   >
                     Loading...
                   </TableCell>
                 </TableRow>
               ) : items.length === 0 ? (
                 <TableRow>
                   <TableCell
                     className="text-center text-muted-foreground"
                     colSpan={columnDefs.length}
                   >
                     {emptyMessage}
                   </TableCell>
                 </TableRow>
               ) : (
                 table.getRowModel().rows.map((row) => (
                   <TableRow
                     className="cursor-pointer"
                     key={row.id}
                     onClick={() => onRowClick?.(row.original as TItem)}
                   >
                     {row.getVisibleCells().map((cell) => (
                       <TableCell key={cell.id}>
                         {flexRender(
                           cell.column.columnDef.cell,
                           cell.getContext(),
                         )}
                       </TableCell>
                     ))}
                   </TableRow>
                 ))
               )}
             </TableBody>
           </Table>
         </div>

         {nextCursor && (
           <div className="flex justify-center">
             <Button
               onClick={() => setCursor(nextCursor)}
               size="sm"
               variant="outline"
             >
               Load more
             </Button>
           </div>
         )}
       </div>
     </NavLayout>
   );
 }

